-- 2026-06-22: knee_meniscectomy — фазы «Путь» + структурированные критерии перехода (K1 мениск колена).
-- Источник: PROTOCOLS/knee/*.md + PROTOCOLS/knee/_extractions_meniscus.json (knee_meniscectomy).
-- Контент в ПАЦИЕНТСКОМ регистре (первичная версия) — источник истины после деплоя AdminContent.
-- Решения Vadim 2026-06-22: нумерация фаз с 1;
--   terminal-фаза несёт критерии возврата к спорту/выписки.
-- Классификация (knee-конвенция, как acl_refresh): measurement = ROM-градусы (knee_flexion/extension_degrees,
--   source='rom') + боль ВАШ (vas_score, source='pain'); всё прочее (сила/LSI/hop/выпот/KOOS/срок) =
--   instructor_check с порогом в тексте label. Идемпотентна: ON CONFLICT DO NOTHING для обеих таблиц.

BEGIN;

-- 1. Фазы knee_meniscectomy
INSERT INTO rehab_phases (program_type, phase_number, title, subtitle, duration_weeks, description, goals, restrictions, criteria_next, icon, color, color_bg, teaser, allowed, pain, daily, red_flags, faq)
VALUES
(
    'knee_meniscectomy', 1,
    'Ранний период: отёк и пробуждение мышцы',
    'Первые недели после операции',
    '0-2',
    'Самый первый этап после артроскопической резекции мениска. Главные задачи — снять отёк и боль, вернуть полное выпрямление колена и заново научить переднюю мышцу бедра включаться. Удалённую часть мениска повредить нельзя, поэтому ранняя нагрузка и движение безопасны и помогают, а не вредят.',
    '["Уменьшить отёк и боль","Вернуть полное выпрямление колена","Снова включить переднюю мышцу бедра","Восстановить уверенную ходьбу"]',
    '["Режим опоры на ногу задаёт хирург — следуйте его указаниям","Не сидите с валиком под коленом: это мешает полному выпрямлению","Не форсируйте долгую ходьбу, пока есть отёк","Избегайте действий, которые усиливают боль и отёк"]',
    '["Колено сгибается минимум до прямого угла","Колено полностью выпрямляется","Можете поднять прямую ногу без провала мышцы бедра","Боль под контролем"]',
    'shield', '#EF4444', '#FEF2F0',
    'Снять отёк, выпрямить колено, включить бедро',
    '["Наступать на ногу с опорой по самочувствию с первого дня","Костыли временно — пока не уйдёт хромота (для походки, не для разгрузки)","Сгибать и выпрямлять колено в комфортном объёме","Лёгкий велотренажёр для подвижности","Холод и приподнятое положение ноги"]',
    '["Небольшой дискомфорт при упражнениях — это норма","Ориентир — боль не выше 3–4 из 10 и стихает к следующему дню","Если боль или отёк нарастают после нагрузки — на день-два снизьте объём, добавьте холод"]',
    '["Несколько коротких занятий в день","Держите ногу приподнятой в покое для оттока отёка","Прикладывайте холод после нагрузки"]',
    '["Боль в икре и отёк голени — срочно к врачу, возможен тромб","Нарастающее покраснение, жар у раны, температура, гной — срочно к врачу","Резко напряжённое, горячее, сильно распухшее колено","Колено заклинило и не выпрямляется"]',
    '[{"q":"Можно ли сразу наступать на ногу?","a":"Да, по самочувствию с первого дня. Удалённую часть мениска повредить нельзя, а ранняя нагрузка помогает снять отёк и сохранить мышцу. Костыли — лишь временно, пока не уйдёт хромота."},{"q":"Колено отекает и побаливает — это нормально?","a":"Лёгкий отёк и дискомфорт в первые дни — обычное дело. Помогают холод, приподнятое положение и работа мышцы бедра. Но если колено резко распухло, стало горячим или появилась боль в икре — сразу к врачу."},{"q":"Правда ли, что наступать на ногу вредно для сустава?","a":"Нет. Разумная ранняя нагрузка не «изнашивает» сустав — наоборот, она помогает унять отёк, сохранить мышцу и быстрее вернуться к привычной жизни."}]'
),
(
    'knee_meniscectomy', 2,
    'Полный объём и сила',
    'Возврат подвижности и силы бедра',
    '2-6',
    'Колено уже спокойнее. Теперь задача — вернуть полный безболезненный объём движений, нарастить силу и выносливость бедра и уйти от костылей при ровной походке. Сила мышц — главная защита колена на годы вперёд.',
    '["Полный безболезненный объём движений","Вернуть силу и выносливость бедра","Нормальная походка без костылей и трости","Баланс и контроль над коленом"]',
    '["Пока избегайте бега, прыжков и резких разворотов","Объём наращивайте постепенно, отслеживая реакцию колена на следующий день"]',
    '["Полный безболезненный объём движений","Нет отёка по проверке колена","Ровная походка без хромоты и без костылей","Повседневные дела без боли"]',
    'dumbbell', '#F59E0B', '#FFF8ED',
    'Полный объём движений, сила бедра, ровная походка',
    '["Полная нагрузка без костылей, когда походка ровная","Приседания в комфортном диапазоне, выпады, подъёмы на ступеньку","Тренажёры (жим ногами, сгибания/разгибания), мостики","Кардио без удара — эллипс, степпер, плавание, велотренажёр","Упражнения на одной ноге и баланс"]',
    '["Тренировки могут давать лёгкую усталость мышц — это нормально","Цель — отсутствие боли и отёка ПОСЛЕ нагрузки","Появился отёк или боль на следующий день — шаг назад по объёму"]',
    '["Регулярные силовые занятия для бедра","Следите за реакцией колена на следующий день после нагрузки"]',
    '["Боль в икре и отёк голени — срочно к врачу, возможен тромб","Признаки инфекции: температура, покраснение, выделения из раны","Стойкий или возвращающийся отёк после нагрузок — сигнал, что прогрессируете слишком быстро","Колено заклинило или ощущение нестабильности"]',
    '[{"q":"Когда можно отказаться от костылей?","a":"Когда идёте ровно, без хромоты и без боли. У большинства это первые 1–2 недели."},{"q":"Не вредно ли приседать и качать ногу?","a":"Нет. Сила бедра — главная защита колена на годы вперёд. Нагрузку наращиваем постепенно, ориентируясь на реакцию колена на следующий день."}]'
),
(
    'knee_meniscectomy', 3,
    'Возврат к бегу и спорту',
    'Бег, прыжки и спорт-специфика',
    '6+',
    'Финальный этап. Задача — довести силу и технику до уровня, который позволяет безопасно бегать, прыгать и вернуться к спорту. Сначала возвращаем бег и лёгкую ударную нагрузку, затем — прыжки и спорт-специфичные движения с разворотами.',
    '["Полная сила и выносливость ноги","Правильная техника движений и приземления","Возврат к работе, бытовым задачам и спорту"]',
    '["К бегу и прыжкам приступайте только без отёка и боли при ударной нагрузке и при достаточной силе бедра","Резкие развороты и контактные виды — в последнюю очередь"]',
    '["Нет отёка и боли","Сила бедра близка к здоровой ноге","Прыжковые тесты на уровне здоровой ноги","Хорошая техника и одобрение куратора"]',
    'trophy', '#EC4899', '#FFF9E6',
    'Бег, прыжки и возврат к спорту по тестам',
    '["Программа «ходьба-бег» при готовности","Плиометрика и прыжковые упражнения","Беговые и «агилити»-дрилы","Спорт-специфичные нагрузки, развороты и контакт — по целям и при хорошем контроле"]',
    '["Допустима мышечная усталость после тренировки","Боль в суставе и отёк после нагрузки — стоп-сигнал, снизьте объём"]',
    '["Держите вес в норме и мышцы сильными — это лучшая защита хряща","После ударных тренировок следите за отёком на следующий день"]',
    '["Новый отёк, боль или ощущение нестабильности при возврате к спорту — пауза и осмотр","Боль в икре и отёк голени — срочно к врачу"]',
    '[{"q":"Когда можно бегать и вернуться в спорт?","a":"К бегу — когда нет отёка, нет боли при лёгком ударе и сила бедра близка к здоровой ноге. К спорту — обычно с 4–12 недель, когда прыжковые тесты и сила достигают около 90% от здоровой ноги и техника хорошая."},{"q":"Правда ли, что нагрузка «износит» сустав?","a":"Сама по себе разумная активность сустав не изнашивает. Важнее держать нормальный вес, сильные мышцы и хорошую технику — это и есть лучшая защита хряща."}]'
)
ON CONFLICT (program_type, phase_number) DO NOTHING;

-- 2. Критерии перехода knee_meniscectomy (JOIN на rehab_phases по program_type+phase_number → phase_id)
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  (1, 'full_ext_p1', 'Колено полностью выпрямляется (разгибание 0°)', 'measurement', 'knee_extension_degrees'::varchar, 'rom'::varchar, '<='::varchar, 0::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'flex_90_p1', 'Колено сгибается минимум до 90°', 'measurement', 'knee_flexion_degrees'::varchar, 'rom'::varchar, '>='::varchar, 90::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 20::smallint, TRUE),
  (1, 'pain_low_p1', 'Боль под контролем — не выше 4 из 10', 'measurement', 'vas_score'::varchar, 'pain'::varchar, '<='::varchar, 4::numeric, NULL::numeric, 7::smallint, NULL::text, NULL::text, 30::smallint, TRUE),
  (1, 'quad_activation_p1', 'Подъём прямой ноги без провала мышцы бедра (проверяет куратор очно)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 40::smallint, TRUE),
  (2, 'full_rom_p2', 'Полный безболезненный объём движений колена (проверяет куратор очно)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (2, 'no_effusion_p2', 'Нет отёка по тесту выжимания (проверяет куратор очно)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 20::smallint, TRUE),
  (2, 'normal_gait_p2', 'Симметричная походка без хромоты и без костылей, полная нагрузка на ногу (проверяет куратор очно)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 30::smallint, TRUE),
  (2, 'adl_no_pain_p2', 'Повседневные дела выполняются без боли', 'self_report', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, 'Получается ли выполнять обычные повседневные дела без боли в колене?'::text, 'Ходьба, лестница, бытовые задачи — оцените, мешает ли боль в течение дня.'::text, 40::smallint, TRUE),
  (3, 'no_effusion_run_p3', 'Возврат к бегу: нет отёка (проверяет куратор очно)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (3, 'no_pain_impact_p3', 'Возврат к бегу: нет боли при ходьбе и лёгкой ударной нагрузке', 'self_report', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, 'Можете ли ходить и выполнять лёгкую ударную нагрузку без боли в колене?'::text, 'Например, лёгкие подскоки на месте или быстрый шаг — без боли в суставе.'::text, 20::smallint, TRUE),
  (3, 'quad_lsi_80_run_p3', 'Возврат к бегу: сила передней мышцы бедра не менее 80% от здоровой ноги (проверяет куратор очно)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 30::smallint, TRUE),
  (3, 'landing_tech_p3', 'Возврат к бегу: хорошая техника приземления (проверяет куратор очно)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 40::smallint, TRUE),
  (3, 'quad_lsi_90_sport_p3', 'Возврат к спорту: сила квадрицепса не менее 90% от здоровой ноги (проверяет куратор очно)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 50::smallint, TRUE),
  (3, 'hop_lsi_90_sport_p3', 'Возврат к спорту: хоп-тесты (одиночный, тройной, перекрёстный) не менее 90% от здоровой ноги (проверяет куратор очно)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 60::smallint, TRUE),
  (3, 'ham_glute_lsi_90_p3', 'Возврат к спорту: сила задней поверхности бедра и ягодичных не менее 90% от здоровой ноги (проверяет куратор очно)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 70::smallint, FALSE),
  (3, 'sls_10_p3', 'Возврат к спорту: присед на одной ноге с правильной техникой, 10 повторов (через сгибание не менее 60°, проверяет куратор очно)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 80::smallint, FALSE),
  (3, 'koos_sport_90_p3', 'Возврат к спорту: KOOS-Sport выше 90% (или иной опросник по решению куратора)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 90::smallint, FALSE),
  (3, 'no_effusion_pain_sport_p3', 'Возврат к спорту: отсутствие отёка и боли (проверяет куратор очно)', 'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, NULL::text, NULL::text, 100::smallint, TRUE),
  (3, 'sport_readiness_p3', 'Возврат к спорту: готовность к спорту и одобрение хирурга/куратора', 'self_report', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 30::smallint, 'Чувствуете ли вы готовность вернуться к своему спорту и есть ли одобрение хирурга или куратора?'::text, 'Оцените уверенность в колене при движениях вашего вида спорта и наличие очного допуска.'::text, 110::smallint, TRUE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'knee_meniscectomy' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
